import os
import json
import time
from flask import Flask, request, jsonify
from Crypto.Cipher import AES
from Crypto.Util.Padding import pad, unpad

app = Flask(__name__)

# Load critical challenge parameters
try:
    with open('challenge_data.json', 'r') as f:
        CHALLENGE_DATA = json.load(f)
    TOKEN_KEY = bytes.fromhex(CHALLENGE_DATA['token_key'])
    MANIFEST_KEY = bytes.fromhex(CHALLENGE_DATA['manifest_key'])
    ENC_FLAG_GCM = CHALLENGE_DATA['enc_flag_gcm']
    FLAG_NONCE = CHALLENGE_DATA['flag_nonce']
    FLAG_TAG = CHALLENGE_DATA['flag_tag']
except Exception:
    exit(1)

@app.route('/api/request_token', methods=['GET'])
def request_token():
    # The token now contains a secret manifest_key required to decrypt the flag later
    token_data = json.dumps({"role": "guest", "m_key": MANIFEST_KEY.hex()})
    iv = os.urandom(16)
    cipher = AES.new(TOKEN_KEY, AES.MODE_CBC, iv)
    ciphertext = cipher.encrypt(pad(token_data.encode(), 16))
    return jsonify({
        "token": ciphertext.hex(),
        "iv": iv.hex()
    })

@app.route('/api/secure_relay', methods=['POST'])
def secure_relay():
    try:
        data = request.get_json(silent=True) or {}
        token_hex = data.get('token')
        iv_hex = data.get('iv')

        if not token_hex or not iv_hex:
            return jsonify({"error": "Missing token or IV"}), 400

        cipher = AES.new(TOKEN_KEY, AES.MODE_CBC, bytes.fromhex(iv_hex))
        plaintext = unpad(cipher.decrypt(bytes.fromhex(token_hex)), 16)
        user_obj = json.loads(plaintext.decode())

        if user_obj.get('role') == 'admin':
            # Only admins receive the GCM-encrypted flag manifest
            return jsonify({
                "status": "Authorized",
                "manifest_blob": ENC_FLAG_GCM,
                "manifest_nonce": FLAG_NONCE,
                "manifest_tag": FLAG_TAG
            })
        else:
            return jsonify({"status": "Unauthorized", "message": "Guest access restricted"}), 403
    except Exception:
        return jsonify({"error": "Internal security error"}), 400

@app.route('/api/telemetry/debug', methods=['POST'])
def telemetry_debug():
    """
    Hardenened Telemetry endpoint: 
    Uses a blind timing-based padding oracle instead of explicit error messages.
    """
    try:
        data = request.get_json(silent=True) or {}
        payload_hex = data.get('payload')
        iv_hex = data.get('iv')

        if not payload_hex or not iv_hex:
            return jsonify({"error": "Missing payload"}), 400

        payload = bytes.fromhex(payload_hex)
        iv = bytes.fromhex(iv_hex)

        padding_valid = False
        try:
            temp_cipher = AES.new(TOKEN_KEY, AES.MODE_CBC, iv)
            decrypted = temp_cipher.decrypt(payload)
            unpad(decrypted, 16)
            padding_valid = True
        except (ValueError, KeyError):
            padding_valid = False

        # Blind Timing Oracle: Successful padding results in a measurable delay.
        # This makes automated exploitation significantly harder and requires timing analysis.
        if padding_valid:
            time.sleep(0.05)

        # Response is identical regardless of padding success/failure
        return jsonify({"status": "error", "message": "Telemetry rejected by gateway"}), 400

    except Exception:
        return jsonify({"error": "System error"}), 500

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

